requests.preRequestScript:
var runId = "run-" + Date.now();
var traceId = "trace-" + Math.floor(Math.random() * 100000);
reqlab.environment.set("runId", runId);
reqlab.environment.set("traceId", traceId);
reqlab.globals.set("suiteGlobal", "global-1");
reqlab.collectionVariables.set("suiteCollection", "collection-1");
reqlab.variables.set("requestOnly", "local-1");
reqlab.request.headers.upsert("X-Run-Id", runId);
reqlab.request.headers.add("X-Trace-Id", traceId);
reqlab.request.setQueryParam("source", "pre-script");
reqlab.console.log("Prepared request runId", runId, "traceId", traceId);

requests.testScript:
reqlab.test("status is 200", function(){
  reqlab.expect(reqlab.response.code).to.equal(200)
});
reqlab.test("header mutation reached server", function(){
  var body = reqlab.response.json();
  reqlab.expect(body.hasRunId).to.equal(true);
  reqlab.expect(body.hasTrace).to.equal(true);
  reqlab.expect(body.runId).to.equal(reqlab.environment.get("runId"));
  reqlab.expect(body.traceId).to.equal(reqlab.environment.get("traceId"));
});
reqlab.test("script variables are readable", function(){
  reqlab.expect(reqlab.globals.get("suiteGlobal")).to.equal("global-1");
  reqlab.expect(reqlab.collectionVariables.get("suiteCollection")).to.equal("collection-1");
  reqlab.expect(reqlab.variables.get("requestOnly")).to.equal("local-1");
});
reqlab.environment.set("lastRunId", reqlab.response.json().runId);

reqlab.test("status is 200", function(){
  reqlab.expect(reqlab.response.code).to.equal(200)
});
reqlab.test("cross-request variable resolved", function(){
  var body = reqlab.response.json();
  reqlab.expect(body.runId).to.equal(reqlab.environment.get("lastRunId"));
  reqlab.expect(body.traceId).to.equal("trace-cross");
});

reqlab.test("status is 200", function(){
  reqlab.expect(reqlab.response.code).to.equal(200)
});
reqlab.test("mutated body reaches server", function(){
  var body = reqlab.response.json();
  reqlab.expect(body.method).to.equal("POST");
  reqlab.expect(body.body).to.include("\"changed\":true");
  reqlab.expect(body.body).to.include("\"source\":\"pre\"");
});

reqlab.test("status is 200", function(){
  reqlab.expect(reqlab.response.code).to.equal(200)
});
reqlab.test("required fields exist", function(){
  var u = reqlab.response.json();
  reqlab.expect(u).to.have.property("id");
  reqlab.expect(u).to.have.property("name");
  reqlab.expect(u).to.have.property("age");
  reqlab.expect(u).to.have.property("type");
