  var u = reqlab.response.json();
  reqlab.expect(u.name).to.equal("Jane");
  reqlab.expect(u.type).to.equal(reqlab.environment.get("expectedUserType"));
  reqlab.expect(typeof u.id).to.equal("string");
  reqlab.expect(typeof u.age).to.equal("number");
  reqlab.expect(u.age).to.be.oneOf([23,24,25]);
});

