  reqlab.expect(reqlab.environment.get("safeGlobal")).to.be.oneOf(["","global-1"]);
  reqlab.expect(reqlab.environment.get("safeCollection")).to.be.oneOf(["","collection-1"]);
  reqlab.expect(reqlab.environment.get("safeLocal")).to.be.oneOf(["","local-1"]);
