});

reqlab.test("comparison syntax set", function(){
  var p = reqlab.response.json().payload;
  reqlab.expect(p.count).to.be.above(1);
  reqlab.expect(p.count).to.be.below(10);
  reqlab.expect(p.count).to.be.at.least(3);
  reqlab.expect(p.count).to.be.at.most(3);
  reqlab.expect(p.title).to.match(/Req/);
  reqlab.expect(p.title).to.include("Req");
  reqlab.expect(p.title).to.not.equal("Other");
  reqlab.expect(p.list).to.have.lengthOf(3);
  reqlab.expect(p.nested).to.have.property("code");
});

